--
-- Table structure for table `incident_fact`
--

DROP TABLE IF EXISTS `incident_fact`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `incident_fact` (
  `incident_id` int NOT NULL AUTO_INCREMENT,
  `attack_type_id` int NOT NULL,
  `severity` enum('Low','Medium','High','Critical') NOT NULL,
  `system_id` int NOT NULL,
  `reported_by` int NOT NULL,
  `date_id` int NOT NULL,
  `incident_timestamp` datetime NOT NULL,
  `response_time_minutes` int DEFAULT NULL COMMENT 'Filled when incident is resolved',
  `description` text,
  `status` enum('Open','Investigating','Resolved','Closed') NOT NULL,
  `created_at` datetime NOT NULL DEFAULT (now()),
  `updated_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`incident_id`),
  KEY `attack_type_id` (`attack_type_id`),
  KEY `system_id` (`system_id`),
  KEY `reported_by` (`reported_by`),
  KEY `idx_date_id` (`date_id`),
  KEY `idx_status` (`status`),
  KEY `idx_severity` (`severity`),
  KEY `idx_timestamp` (`incident_timestamp`),
  CONSTRAINT `incident_fact_ibfk_1` FOREIGN KEY (`attack_type_id`) REFERENCES `attack_dim` (`attack_type_id`),
  CONSTRAINT `incident_fact_ibfk_2` FOREIGN KEY (`system_id`) REFERENCES `system_dim` (`system_id`),
  CONSTRAINT `incident_fact_ibfk_3` FOREIGN KEY (`reported_by`) REFERENCES `user_dim` (`user_id`),
  CONSTRAINT `incident_fact_ibfk_4` FOREIGN KEY (`date_id`) REFERENCES `date_dim` (`date_id`)
) ENGINE=InnoDB AUTO_INCREMENT=81 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

